module gray_code_counter (
    input clk,
    input rst,
    output reg [2:0] gray
);
    reg [2:0] counter_value;

    always @(posedge clk or posedge rst) begin
        if (rst)
            counter_value <= 3'b000;
        else
            counter_value <= counter_value + 1;
    end

    always @(counter_value) begin
        gray = counter_value ^ (counter_value >> 1);
    end
endmodule
